#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-06

# Snapshot tests for render-ascii.sh patterns × char-sets.
# Update goldens with: UPDATE_SNAPSHOTS=1 bash tests/unit/test-ascii-snapshots.sh
#
# Coverage: 4 implemented patterns × 5 sets = 20 goldens.

set -euo pipefail

ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
RENDER="$ROOT/scripts/render-ascii.sh"
GOLDEN_DIR="$ROOT/tests/fixtures/ascii/golden"
TREE_FIXTURE="$ROOT/tests/fixtures/ascii/tree-sample.txt"

[ -x "$RENDER" ] || { echo "✗ render-ascii.sh not executable at $RENDER"; exit 1; }
[ -f "$TREE_FIXTURE" ] || { echo "✗ tree fixture missing: $TREE_FIXTURE"; exit 1; }
mkdir -p "$GOLDEN_DIR"

UPDATE="${UPDATE_SNAPSHOTS:-0}"
fail=0
pass=0
updated=0

render_one() {
  local pattern="$1" set="$2"
  case "$pattern" in
    box)          "$RENDER" box          --set "$set" --width 40 --label "Backend service" ;;
    progress-bar) "$RENDER" progress-bar --set "$set" --width 40 --label 75 ;;
    sparkline)    "$RENDER" sparkline    --set "$set" --values "1,3,2,5,4,7,6,8" --label "cache" ;;
    tree)         "$RENDER" tree         --set "$set" < "$TREE_FIXTURE" ;;
    *)            echo "unknown pattern: $pattern" >&2; return 1 ;;
  esac
}

PATTERNS=(box progress-bar sparkline tree)
SETS=(default emphasis title soft portable)

for pattern in "${PATTERNS[@]}"; do
  for set in "${SETS[@]}"; do
    golden="$GOLDEN_DIR/${pattern}-${set}.golden.txt"
    actual=$(render_one "$pattern" "$set")

    if [ "$UPDATE" = "1" ] || [ ! -f "$golden" ]; then
      printf '%s\n' "$actual" > "$golden"
      printf '⊕ wrote %s-%s\n' "$pattern" "$set"
      updated=$((updated + 1))
      continue
    fi

    expected=$(cat "$golden")
    if [ "$actual" = "$expected" ]; then
      pass=$((pass + 1))
    else
      printf '✗ %s-%s drift\n' "$pattern" "$set"
      # silent: best-effort (diff exits 1 when differences exist; we want to print and continue)
      diff_out=$(diff <(printf '%s\n' "$expected") <(printf '%s\n' "$actual") | head -10) || true
      printf '%s\n' "$diff_out"
      fail=$((fail + 1))
    fi
  done
done

printf '\n'
if [ "$UPDATE" = "1" ]; then
  printf '⊕ updated %d golden(s)\n' "$updated"
  exit 0
fi
printf '✓ %d pass · ✗ %d fail · ⊕ %d new\n' "$pass" "$fail" "$updated"
[ "$fail" -eq 0 ] || exit 1
